// const MODBUS_APPSTORE_URL = "apps.apple.com/sa/app/modbus-tcp-station/id6757790321";

const MODBUS_DEEPLINK = "macappstore://apps.apple.com/sa/app/modbus-tcp-station/id6757790321";
