// ── Screens enum ──────────────────────────────────────────────────────────────
const S = { SPLASH:"splash", WELCOME:"welcome", SIGNIN:"signin", SIGNUP:"signup", FORGOT:"forgot", VERIFY:"verify", DASHBOARD:"dashboard" };

export default function App() {
  const [screen, setScreen]   = useState(S.SPLASH);
  const [user,   setUser]     = useState(null);
  const [loading,setLoading]  = useState(false);
  const [alert,  setAlert]    = useState(null);
  const [showModal,setShowModal] = useState(false);

  // sign-in fields
  const [siEmail, setSiEmail] = useState("");
  const [siPass,  setSiPass]  = useState("");
  const [remember,setRemember]= useState(false);

  // sign-up fields
  const [suName,    setSuName]    = useState("");
  // const [suId,      setSuId]      = useState("");
  const [suEmail,   setSuEmail]   = useState("");
  // const [suPhone,   setSuPhone]   = useState("");
  const [suPass,    setSuPass]    = useState("");
  const [suConfirm, setSuConfirm] = useState("");
  const [terms,     setTerms]     = useState(false);

  // forgot password
  const [fpEmail, setFpEmail] = useState("");
  const [fpSent,  setFpSent]  = useState(false);

  useEffect(()=>{
    const el = document.createElement("style");
    el.textContent = CSS;
    document.head.appendChild(el);
    return ()=>el.remove();
  },[]);

  useEffect(()=>{
    (async()=>{
      const {data} = await supabase.auth.getSession();
      if(data.session?.user){ setUser(data.session.user); setScreen(S.DASHBOARD); }
    })();
    const {data:L} = supabase.auth.onAuthStateChange((_,s)=>{
      if(s?.user){ setUser(s.user); setScreen(S.DASHBOARD); }
      else setUser(null);
    });
    return ()=>L.subscription.unsubscribe();
  },[]);

  const flash = (msg, type="error") => { setAlert({msg,type}); setTimeout(()=>setAlert(null),4000); };

  const doSignIn = async () => {
    if(!siEmail||!siPass) return flash("Please fill in all fields.");
    setLoading(true);
    const {error} = await supabase.auth.signInWithPassword({email:siEmail,password:siPass});
    setLoading(false);
    if(error) flash(error.message);
  };

  const validatePassword = (p) => {
    if(p.length < 8) return "Password must be at least 8 characters.";
    if(!/[A-Z]/.test(p)) return "Password must contain at least one uppercase letter.";
    if(!/[a-z]/.test(p)) return "Password must contain at least one lowercase letter.";
    if(!/[0-9]/.test(p)) return "Password must contain at least one number.";
    return null;
  };

  const doSignUp = async () => {
    if(!suName||!suEmail||!suPass||!suConfirm) return flash("Please fill in all fields.");
    if(suPass!==suConfirm) return flash("Passwords do not match.");
    const pwErr = validatePassword(suPass);
    if(pwErr) return flash(pwErr);
    if(!terms) return flash("Please accept the Terms & Conditions.");
    setLoading(true);
    const {error} = await supabase.auth.signUp({
      email:suEmail, password:suPass,
      options:{data:{full_name:suName}}
    });
    setLoading(false);
    if(error) flash(error.message);
    else setScreen(S.VERIFY);
  };

  const doForgot = async () => {
    if(!fpEmail) return flash("Please enter your email.");
    setLoading(true);
    const {error} = await supabase.auth.resetPasswordForEmail(fpEmail);
    setLoading(false);
    if(error) flash(error.message);
    else setFpSent(true);
  };

  const doGoogleSignIn = async () => {
    const {error} = await supabase.auth.signInWithOAuth({
      provider: "google",
      options: {
        redirectTo: window.location.origin,
        queryParams: { access_type: "offline", prompt: "consent" }
      }
    });
    if(error) flash("Google sign-in failed: " + error.message);
  };

  const doAppleSignIn = async () => {
    const {error} = await supabase.auth.signInWithOAuth({
      provider: "apple",
      options: { redirectTo: window.location.origin }
    });
    if(error) flash("Apple sign-in failed: " + error.message);
  };

  const doLogout = async () => {
    await supabase.auth.signOut();
    setUser(null); setScreen(S.SPLASH);
  };

  const launchModbus = () => {
    const t = Date.now();
    window.location.href = MODBUS_DEEPLINK;
    setTimeout(()=>{ if(Date.now()-t<1500) window.open(MODBUS_APPSTORE_URL,"_blank"); },800);
    setShowModal(false);
  };
  

  // const now     = new Date();
  // const timeStr = now.toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit",hour12:false});
   const uName   = user?.user_metadata?.full_name ?? user?.email?.split("@")[0] ?? "User";
  const uInit   = uName[0]?.toUpperCase() ?? "U";

  return (
    <div className="phone">
      <div className="notch"/>
      <div className="sbar">
        {/* <span className="sbar-time">{timeStr}</span> */}
        
      </div>

      {/* ══════════ SPLASH ══════════ */}
      {screen===S.SPLASH && (
        <div className="screen splash">

          {/* ── HEADER: Full-width YU logo, stretched edge to edge ── */}
          <div className="sp-header"><img src="data:image/png;base64," alt="Al Yamamah University" className="sp-logo-img"/></div>

          {/* ── Generator photo: professional industrial image ── */}
          <div className="sp-photo-wrap">
            <img
              src="data:image/png;base64,"
              alt="Industrial Power Generator"
              className="sp-photo"
              onError={e => {
                e.target.src = "https://upload.wikimedia.org/wikipedia/commons/thumb/3/3e/Diesel_generator_2.jpg/800px-Diesel_generator_2.jpg";
                e.target.onerror = null;
              }}
            />
            <div className="sp-photo-overlay"/>
            <div className="sp-photo-badge">⚡ Industrial Power Generator</div>
          </div>

          {/* ── Project title ── */}
          <div className="sp-title-block">
            <div className="sp-badge">MULTIDISCIPLINARY GRADUATION PROJECT · Spring 2026</div>
            <div className="sp-headline">
              Smart &amp; Sustainable Automated Design of a Scheduled Power Generator with Backup Control in Case of Failure
            </div>
          </div>

          {/* ── Teams box ── */}
          <div className="sp-box">

            <div className="sp-team-section">
              <div className="sp-team-label ced-label">Students — CED Team</div>
              <div className="sp-team-names">Nagam Radi &nbsp;·&nbsp; Reem Alshawi &nbsp;·&nbsp;Sarah Alothman &nbsp;·&nbsp; Sema Birakdar &nbsp;·&nbsp; Reema Alabdullah</div>
            </div>

            <div className="sp-divline"/>

            <div className="sp-team-section">
              <div className="sp-team-label ied-label">Students — IED Team</div>
              <div className="sp-team-names">Abdulrahman Allift &nbsp;·&nbsp; Zaid Alfaraj &nbsp;·&nbsp; Jouma Akil &nbsp;·&nbsp; Sultan Almetari</div>
            </div>

            <div className="sp-divline"/>

            <div className="sp-team-section">
              <div className="sp-team-label sup-label">Supervisors</div>
              <div className="sp-team-names">Prof. Ali &nbsp;- &nbsp; Ms. Sara</div>
            </div>

          </div>

          {/* ── Enter button ── */}
          <div className="sp-enter">
            <button className="btn-primary" onClick={()=>setScreen(S.WELCOME)}>Enter →</button>
          </div>

        </div>
      )}

      {/* ══════════ WELCOME ══════════ */}
      {screen===S.WELCOME && (
        <div className="screen welcome">
          <div className="wc-body">
            <div style={{display:"flex",justifyContent:"center",marginBottom:8}}>
              <GeneratorSVG/>
            </div>
            <h2 className="wc-title">Welcome Back</h2>
            <button className="btn-primary" onClick={()=>setScreen(S.SIGNIN)}>Sign In</button>
            <button className="btn-outline" style={{marginTop:12}} onClick={()=>setScreen(S.SIGNUP)}>Sign Up</button>
          </div>
          <div className="wc-foot">
            <div className="wc-foot-tagline">CIS492 · Computer Engineering<br/>IEG491 · Industrial Engineering</div>
          </div>
        </div>
      )}

      {/* ══════════ SIGN IN ══════════ */}
      {screen===S.SIGNIN && (
        <div className="screen form-screen">
          <button className="back-btn" onClick={()=>setScreen(S.WELCOME)}>← Back</button>
          <div style={{display:"flex",justifyContent:"center",marginBottom:12}}>
            <GeneratorSVG/>
          </div>
          <h2 className="form-title">Sign in to your account</h2>
          {alert && <div className={`alert ${alert.type}`}>{alert.msg}</div>}

          <div className="field">
            <label>Email</label>
            <div className="inp-wrap">
              <span className="inp-ico">✉</span>
              <input type="email" placeholder="your.email@yu.edu.sa"
                value={siEmail} onChange={e=>setSiEmail(e.target.value)} style={{paddingLeft:34}}/>
            </div>
          </div>
          <div className="field">
            <label>Password</label>
            <div className="inp-wrap">
              <span className="inp-ico">🔒</span>
              <input type="password" placeholder="••••••••"
                value={siPass} onChange={e=>setSiPass(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&doSignIn()} style={{paddingLeft:34}}/>
            </div>
            {siPass.length > 0 && (
              <div className="pw-hint">
                <span className={siPass.length >= 8 ? "ph ok" : "ph"}>✓ 8+ characters</span>
                <span className={/[A-Z]/.test(siPass) ? "ph ok" : "ph"}>✓ Uppercase</span>
                <span className={/[a-z]/.test(siPass) ? "ph ok" : "ph"}>✓ Lowercase</span>
                <span className={/[0-9]/.test(siPass) ? "ph ok" : "ph"}>✓ Number</span>
              </div>
            )}
          </div>

          <div className="row-between" style={{marginBottom:18}}>
            <label className="check-lbl">
              <input type="checkbox" checked={remember} onChange={e=>setRemember(e.target.checked)}/>
              <span>Remember me for 30 days</span>
            </label>
            <span className="lnk" onClick={()=>{ setAlert(null); setScreen(S.FORGOT); }}>Forget Password?</span>
          </div>

          <button className="btn-primary" onClick={doSignIn} disabled={loading}>
            {loading?<span className="spin"/>:"Sign In →"}
          </button>

          <div className="form-foot">
            Don't have an account? <span className="lnk" onClick={()=>setScreen(S.SIGNUP)}>Sign up</span>
          </div>
        </div>
      )}

      {/* ══════════ SIGN UP ══════════ */}
      {screen===S.SIGNUP && (
        <div className="screen form-screen">
          <button className="back-btn" onClick={()=>setScreen(S.WELCOME)}>← Back</button>
          <h2 className="form-title">Personal Details</h2>
          {alert && <div className={`alert ${alert.type}`}>{alert.msg}</div>}
          <div className="field"><input placeholder="Full Name"              value={suName}    onChange={e=>setSuName(e.target.value)}/></div>
          <div className="field"><input type="email" placeholder="Email (@yu.edu.sa)" value={suEmail}   onChange={e=>setSuEmail(e.target.value)}/></div>
          <div className="field">
            <input type="password" placeholder="Password" value={suPass} onChange={e=>setSuPass(e.target.value)}/>
            <div className="pw-criteria">
              <div className={`pw-rule ${suPass.length>=8?"ok":""}`}>✓ At least 8 characters</div>
              <div className={`pw-rule ${/[A-Z]/.test(suPass)?"ok":""}`}>✓ One uppercase letter</div>
              <div className={`pw-rule ${/[a-z]/.test(suPass)?"ok":""}`}>✓ One lowercase letter</div>
              <div className={`pw-rule ${/[0-9]/.test(suPass)?"ok":""}`}>✓ One number</div>
            </div>
          </div>
          <div className="field"><input type="password" placeholder="Confirm Password" value={suConfirm} onChange={e=>setSuConfirm(e.target.value)}/></div>
          <label className="check-lbl" style={{marginBottom:16,fontSize:12}}>
            <input type="checkbox" checked={terms} onChange={e=>setTerms(e.target.checked)}/>
            <span>I agree to the <span className="lnk">Terms &amp; Conditions</span></span>
          </label>
          <button className="btn-primary" onClick={doSignUp} disabled={loading}>
            {loading?<span className="spin"/>:"Create Account →"}
          </button>
          <div className="form-foot">
            Already have an account? <span className="lnk" onClick={()=>setScreen(S.SIGNIN)}>Sign in</span>
          </div>
        </div>
      )}

      {/* ══════════ FORGOT PASSWORD ══════════ */}
      {screen===S.FORGOT && (
        <div className="screen form-screen">
          <button className="back-btn" onClick={()=>setScreen(S.SIGNIN)}>← Back</button>
          <div style={{fontSize:60,textAlign:"center",margin:"20px 0 10px"}}>🔑</div>
          <h2 className="form-title" style={{textAlign:"center"}}>Forget Password</h2>
          {!fpSent ? (
            <>
              <p style={{fontSize:13,color:"var(--muted)",textAlign:"center",lineHeight:1.7,fontFamily:"'DM Mono',monospace",marginBottom:22}}>
                Enter your registered email to receive a reset link.
              </p>
              {alert && <div className={`alert ${alert.type}`}>{alert.msg}</div>}
              <div className="field">
                <label>Email</label>
                <div className="inp-wrap">
                  <span className="inp-ico">✉</span>
                  <input type="email" placeholder="your.email@yu.edu.sa"
                    value={fpEmail} onChange={e=>setFpEmail(e.target.value)} style={{paddingLeft:34}}/>
                </div>
              </div>
              <button className="btn-primary" onClick={doForgot} disabled={loading}>
                {loading?<span className="spin"/>:"Send Reset Link →"}
              </button>
              <button className="btn-outline" style={{marginTop:10}} onClick={()=>setScreen(S.SIGNIN)}>← Back to Sign In</button>
            </>
          ) : (
            <>
              <div style={{fontSize:60,textAlign:"center",margin:"10px 0"}}>✅</div>
              <p style={{fontSize:14,color:"var(--accent)",textAlign:"center",lineHeight:1.7,fontFamily:"'DM Mono',monospace",marginBottom:24}}>
                Reset link sent! Check your inbox and follow the instructions.
              </p>
              <button className="btn-primary" onClick={()=>{ setScreen(S.SIGNIN); setFpSent(false); setFpEmail(""); }}>
                Back to Sign In
              </button>
            </>
          )}
        </div>
      )}

      {/* ══════════ VERIFY EMAIL ══════════ */}
      {screen===S.VERIFY && (
        <div className="screen form-screen" style={{alignItems:"stretch"}}>
          <div style={{fontSize:64,textAlign:"center",margin:"36px 0 18px"}}>✉️</div>
          <h2 className="form-title" style={{textAlign:"center"}}>Verify Your Email</h2>
          <p style={{fontSize:13,color:"var(--muted)",textAlign:"center",lineHeight:1.7,fontFamily:"'DM Mono',monospace",marginBottom:24}}>
            A verification link has been sent to your email address. Please check your inbox and click the link to activate your account.
          </p>
          <button className="btn-primary" onClick={()=>setScreen(S.SIGNIN)}>Go to Sign In</button>
          <div className="form-foot"><span className="lnk">Resend verification email</span></div>
        </div>
      )}

      {/* ══════════ DASHBOARD ══════════ */}
      {screen===S.DASHBOARD && (
        <div className="screen dashboard">
          <div className="dash-head">
            <div>
              <div className="greeting">Hello, {uName.split(" ")[0]} 👋</div>
              <div className="greeting-sub">Ready to connect</div>
            </div>
            <div className="avatar">{uInit}</div>
          </div>

          <div className="dash-divider"/>

          <div className="status-card">
            <div className="status-dot"/>
            <div>
              <div className="status-val">Authenticated</div>
              <div className="status-text">{user.email}</div>
            </div>
          </div>

          <div className="info-grid">
            {[
              {label:"Protocol", val:"Modbus TCP/RTU"},
              {label:"Status",   val:"● Online",  accent:true},
              {label:"Port",     val:"502"},
              {label:"Mode",     val:"Master"},
            ].map(t=>(
              <div className="info-tile" key={t.label}>
                <div className="info-tile-label">{t.label}</div>
                <div className="info-tile-value" style={t.accent?{fontSize:14,color:"var(--accent)",WebkitTextFillColor:"var(--accent)"}:{fontSize:14,fontWeight:700}}>{t.val}</div>
              </div>
            ))}
          </div>

          <div className="divider"/>

          <div className="launch-section">
            <h3>Launch App</h3>
            <div className="app-badge">
              <div className="app-icon">📡</div>
              <div className="app-info">
                <div className="app-name">Modbus Station</div>
                <div className="app-sub">Available on App Store · iOS</div>
              </div>
              <span style={{fontSize:11,color:"var(--accent)",fontFamily:"'DM Mono',monospace"}}>iOS</span>
            </div>
            <button className="btn-launch" onClick={()=>setShowModal(true)}>
              <span style={{fontSize:22}}>📡</span>
              <span>Open Modbus Station</span>
              <span style={{marginLeft:"auto",fontSize:18}}>→</span>
            </button>
          </div>

          <button className="btn-secondary" onClick={doLogout}>Sign Out</button>
        </div>
      )}

      {/* ══════════ LAUNCH MODAL ══════════ */}
      {showModal && (
        <div className="modal-overlay" onClick={()=>setShowModal(false)}>
          <div className="modal" onClick={e=>e.stopPropagation()}>
            <div className="modal-handle"/>
            <h3>Open Modbus Station?</h3>
            <p>This will launch the Modbus Station app. If not installed, you'll be redirected to the App Store.</p>
            <div className="modal-btns">
              <button className="modal-btn-cancel" onClick={()=>setShowModal(false)}>Cancel</button>
              <button className="modal-btn-open"   onClick={launchModbus}>Open App</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── CSS ────────────────────────────────────────────────────────────────────────
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans+Arabic:wght@400;600;700&family=DM+Mono:wght@300;400;500&family=Syne:wght@400;600;700;800&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0;}
:root{
  --bg:#0a0c10;--surface:#111318;--border:#1e2130;
  --accent:#00d4aa;--accent2:#0094ff;--danger:#ff4757;
  --text:#e8eaf0;--muted:#5a6070;--card:#13161e;
  --navy:#0f1829;--gold:#c9a84c;
}
body{background:var(--bg);font-family:'Syne',sans-serif;color:var(--text);min-height:100vh;display:flex;align-items:center;justify-content:center;}
#root{width:100%;min-height:100vh;display:flex;align-items:center;justify-content:center;}
/* .notch{position:absolute;top:0;left:50%;transform:translateX(-50%);width:120px;height:34px;background:var(--bg);border-radius:0 0 20px 20px;z-index:10;} */
/* PHONE */
.phone{width:430px;height:932px;background:var(--bg);border-radius:0 0 20px 20px;border:none;overflow:hidden;position:relative;display:flex;flex-direction:column;box-shadow:none;}
.sbar{height:54px;display:flex;align-items:flex-end;justify-content:space-between;padding:0 28px 10px;flex-shrink:0;z-index:5;position:relative;}
.sbar-time{font-family:'DM Mono',monospace;font-size:13px;font-weight:500;}
.sbar-icons{font-size:11px;color:var(--text);}

/* SCREENS */
.screen{flex:1;display:flex;flex-direction:column;overflow-y:auto;animation:fadeIn 0.4s ease;}
@keyframes fadeIn{from{opacity:0;transform:translateY(14px);}to{opacity:1;transform:translateY(0);}}

/* ── SPLASH ── */
.splash{padding:0;background:var(--bg);display:flex;flex-direction:column;}

/* Header: YU logo full width, black bg, professional padding */
.sp-header{width:100%;background:#000;line-height:0;position:relative;border-bottom:1px solid rgba(0,212,170,0.15);}
.sp-logo-img{width:100%;height:auto;display:block;object-fit:contain;object-position:center;padding:16px 32px;background:#000;max-height:90px;}

/* TCP/Modbus photo — embedded, crisp, no fade needed */
.sp-photo-wrap{position:relative;width:100%;height:210px;background:#03091a;overflow:hidden;}
.sp-photo{width:100%;height:100%;object-fit:cover;object-position:center center;display:block;
  filter:brightness(1.08) saturate(1.15) contrast(1.05);
  mix-blend-mode:lighten;}
.sp-photo-overlay{
  position:absolute;inset:0;
  background:
    radial-gradient(ellipse at center, transparent 40%, #03091a 100%),
    linear-gradient(to top, #03091a 0%, transparent 40%),
    linear-gradient(to bottom, #03091a 0%, transparent 25%),
    linear-gradient(to left, #03091a 0%, transparent 25%),
    linear-gradient(to right, #03091a 0%, transparent 25%);}
.sp-photo-badge{position:absolute;bottom:10px;left:14px;font-size:10px;font-weight:700;color:var(--accent);font-family:'DM Mono',monospace;letter-spacing:2px;text-transform:uppercase;}

/* Project title */
.sp-title-block{padding:12px 18px 8px;text-align:center;}
.sp-badge{display:inline-block;background:rgba(0,212,170,0.1);border:1px solid rgba(0,212,170,0.25);color:var(--accent);font-size:8px;font-weight:700;letter-spacing:1.5px;padding:3px 10px;border-radius:20px;margin-bottom:7px;font-family:'DM Mono',monospace;}
.sp-headline{font-size:11.5px;font-weight:700;color:var(--text);line-height:1.55;}

/* Teams box */
.sp-box{margin:0 16px;background:var(--card);border:1px solid var(--border);border-radius:16px;padding:14px 16px;display:flex;flex-direction:column;gap:10px;}
.sp-team-section{display:flex;flex-direction:column;gap:4px;}
.sp-team-label{font-size:9px;font-weight:800;letter-spacing:1.8px;text-transform:uppercase;font-family:'DM Mono',monospace;}
.ced-label{color:#60a5fa;}
.ied-label{color:var(--accent);}
.sup-label{color:var(--gold);}
.sp-team-names{font-size:11.5px;color:#e5e7eb;font-family:'DM Mono',monospace;line-height:1.5;}
.sp-divline{height:1px;background:var(--border);}

.sp-enter{padding:12px 18px 28px;}


/* Password criteria */
.pw-criteria{display:grid;grid-template-columns:1fr 1fr;gap:4px;margin-top:8px;padding:10px 12px;background:rgba(255,255,255,0.03);border-radius:8px;border:1px solid var(--border);}
.pw-rule{font-size:10.5px;font-family:'DM Mono',monospace;color:var(--muted);transition:color 0.2s;}
.pw-rule.ok{color:var(--accent);}

/* WELCOME */
.welcome{background:var(--bg);padding:20px 28px 32px;justify-content:space-between;}
.wc-body{flex:1;display:flex;flex-direction:column;align-items:center;padding-bottom:12px;}
.wc-title{font-size:26px;font-weight:800;color:var(--text);text-align:center;margin:10px 0 20px;}
.wc-body .btn-primary,.wc-body .btn-outline{width:100%;}
.wc-foot{border-top:1px solid var(--border);padding:14px 0 8px;display:flex;justify-content:center;}
.wc-foot-tagline{font-size:11px;font-family:'DM Mono',monospace;color:var(--muted);letter-spacing:1.5px;text-transform:uppercase;}
.wc-foot-inner{background:var(--navy);padding:14px 20px;border-radius:14px;border:1px solid rgba(201,168,76,0.3);}
.dash-divider{height:1px;background:var(--border);}

/* FORMS */
.form-screen{padding:16px 28px 32px;gap:0;}
.back-btn{background:none;border:none;color:var(--muted);font-size:13px;font-family:'Syne',sans-serif;cursor:pointer;padding:0 0 12px;text-align:left;width:fit-content;}
.back-btn:hover{color:var(--accent);}
.form-title{font-size:20px;font-weight:800;color:var(--text);margin-bottom:16px;}
.field{margin-bottom:12px;}
.field label{display:block;font-size:11px;font-weight:600;letter-spacing:1.5px;text-transform:uppercase;color:var(--muted);margin-bottom:6px;font-family:'DM Mono',monospace;}
.field input,.inp-wrap input{width:100%;padding:13px 14px;background:var(--card);border:1.5px solid var(--border);border-radius:12px;color:var(--text);font-size:14px;font-family:'DM Mono',monospace;outline:none;transition:border-color 0.2s,box-shadow 0.2s;}
.field input:focus,.inp-wrap input:focus{border-color:var(--accent);box-shadow:0 0 0 3px rgba(0,212,170,0.12);}
input::placeholder{color:var(--muted);}
.inp-wrap{position:relative;}
.inp-ico{position:absolute;left:11px;top:50%;transform:translateY(-50%);font-size:14px;color:var(--muted);pointer-events:none;}
.row-between{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px;}
.check-lbl{display:flex;align-items:center;gap:8px;font-size:12px;color:var(--muted);cursor:pointer;line-height:1.4;}
.check-lbl input[type=checkbox]{width:14px;height:14px;accent-color:var(--accent);flex-shrink:0;}
.lnk{color:var(--accent);cursor:pointer;font-size:12px;}
.lnk:hover{text-decoration:underline;}
.form-foot{text-align:center;font-size:13px;color:var(--muted);margin-top:14px;font-family:'DM Mono',monospace;}
.or-div{display:flex;align-items:center;gap:12px;font-size:11px;color:var(--muted);margin:16px 0 12px;font-family:'DM Mono',monospace;}
.or-div::before,.or-div::after{content:'';flex:1;height:1px;background:var(--border);}

/* DASHBOARD */
.dashboard{flex:1;display:flex;flex-direction:column;gap:16px;padding:20px 28px 40px;animation:fadeIn 0.4s ease;overflow-y:auto;}
.dash-head{display:flex;justify-content:space-between;align-items:center;padding-top:8px;}
.greeting{font-size:22px;font-weight:800;}
.greeting-sub{font-size:13px;color:var(--muted);font-family:'DM Mono',monospace;margin-top:2px;}
.avatar{width:44px;height:44px;background:linear-gradient(135deg,var(--accent),var(--accent2));border-radius:14px;display:flex;align-items:center;justify-content:center;font-size:18px;box-shadow:0 4px 12px rgba(0,212,170,0.3);}
.status-card{background:var(--card);border:1px solid var(--border);border-radius:18px;padding:18px;display:flex;align-items:center;gap:14px;}
.status-dot{width:10px;height:10px;border-radius:50%;background:var(--accent);box-shadow:0 0 10px var(--accent);animation:pulse 2s infinite;}
@keyframes pulse{0%,100%{box-shadow:0 0 8px var(--accent);}50%{box-shadow:0 0 18px var(--accent);}}
.status-text{font-size:13px;color:var(--muted);font-family:'DM Mono',monospace;}
.status-val{font-size:15px;font-weight:700;color:var(--text);}
.info-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
.info-tile{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:16px;}
.info-tile-label{font-size:10px;font-family:'DM Mono',monospace;color:var(--muted);text-transform:uppercase;letter-spacing:1px;margin-bottom:6px;}
.info-tile-value{font-size:20px;font-weight:800;background:linear-gradient(135deg,var(--text),var(--muted));-webkit-background-clip:text;-webkit-text-fill-color:transparent;}
.divider{height:1px;background:var(--border);margin:4px 0;}
.launch-section h3{font-size:13px;font-family:'DM Mono',monospace;color:var(--muted);text-transform:uppercase;letter-spacing:2px;margin-bottom:14px;}
.app-badge{display:flex;align-items:center;gap:10px;margin-bottom:14px;padding:12px 14px;background:rgba(0,148,255,0.06);border-radius:12px;border:1px solid rgba(0,148,255,0.15);}
.app-icon{width:44px;height:44px;border-radius:10px;background:linear-gradient(135deg,#1a3a6e,#0a1e42);display:flex;align-items:center;justify-content:center;font-size:22px;border:1px solid rgba(0,148,255,0.3);}
.app-info{flex:1;}
.app-name{font-size:14px;font-weight:700;}
.app-sub{font-size:11px;font-family:'DM Mono',monospace;color:var(--muted);}

/* BUTTONS */
.btn-primary{width:100%;padding:15px;background:linear-gradient(135deg,var(--accent),var(--accent2));border:none;border-radius:14px;color:#000;font-size:15px;font-weight:700;font-family:'Syne',sans-serif;cursor:pointer;letter-spacing:0.3px;transition:opacity 0.2s,transform 0.15s;box-shadow:0 8px 24px rgba(0,212,170,0.25);}
.btn-primary:hover{opacity:0.9;transform:translateY(-1px);}
.btn-primary:active{transform:scale(0.98);}
.btn-primary:disabled{opacity:0.5;cursor:not-allowed;transform:none;}
.btn-outline{width:100%;padding:14px;background:transparent;border:1.5px solid var(--border);border-radius:14px;color:var(--muted);font-size:14px;font-family:'Syne',sans-serif;cursor:pointer;transition:all 0.2s;}
.btn-outline:hover{border-color:var(--accent);color:var(--accent);}
.btn-launch{width:100%;padding:20px;background:linear-gradient(135deg,#1a2540,#0d1829);border:1.5px solid rgba(0,148,255,0.3);border-radius:18px;color:var(--text);font-size:16px;font-weight:700;font-family:'Syne',sans-serif;cursor:pointer;transition:all 0.25s;display:flex;align-items:center;justify-content:center;gap:12px;box-shadow:0 0 40px rgba(0,148,255,0.1);position:relative;overflow:hidden;}
.btn-launch:hover{border-color:var(--accent2);transform:translateY(-2px);}
.btn-secondary{width:100%;padding:14px;background:transparent;border:1.5px solid var(--border);border-radius:14px;color:var(--muted);font-size:13px;font-family:'Syne',sans-serif;cursor:pointer;margin-top:4px;transition:all 0.2s;}
.btn-secondary:hover{border-color:var(--danger);color:var(--danger);}
.btn-social{width:100%;padding:13px;background:var(--card);border:1.5px solid var(--border);border-radius:12px;color:var(--text);font-size:14px;font-family:'Syne',sans-serif;cursor:pointer;display:flex;align-items:center;justify-content:center;gap:10px;font-weight:600;transition:border-color 0.2s,box-shadow 0.2s;}
.btn-social:hover{border-color:var(--accent);box-shadow:0 2px 10px rgba(0,212,170,0.1);}
.btn-social.dark{background:#1a1a2e;border-color:#2a2a4a;}
.btn-social.dark:hover{border-color:var(--accent);}

/* ALERT */
.alert{padding:12px 14px;border-radius:10px;font-size:13px;margin-bottom:14px;font-family:'DM Mono',monospace;line-height:1.5;animation:fadeIn 0.3s ease;}
.alert.error{background:rgba(255,71,87,0.1);border:1px solid rgba(255,71,87,0.3);color:#ff6b78;}
.alert.success{background:rgba(0,212,170,0.1);border:1px solid rgba(0,212,170,0.3);color:var(--accent);}

/* SPINNER */
.spin{display:inline-block;width:16px;height:16px;border:2px solid rgba(0,0,0,0.3);border-top-color:#000;border-radius:50%;animation:spin 0.7s linear infinite;}
@keyframes spin{to{transform:rotate(360deg);}}
/* Password strength hint */
.pw-hint{display:grid;grid-template-columns:1fr 1fr;gap:4px 8px;margin-top:8px;padding:8px 12px;background:rgba(255,255,255,0.03);border-radius:8px;border:1px solid var(--border);}
.ph{font-size:10.5px;font-family:'DM Mono',monospace;color:var(--muted);transition:color 0.2s;}
.ph.ok{color:var(--accent);}

/* MODAL */
.modal-overlay{position:absolute;inset:0;background:rgba(0,0,0,0.7);backdrop-filter:blur(4px);display:flex;align-items:flex-end;z-index:20;animation:fadeIn 0.3s ease;}
.modal{background:var(--card);border-radius:28px 28px 0 0;border:1px solid var(--border);padding:28px;width:100%;animation:slideUp 0.35s cubic-bezier(0.32,0.72,0,1);}
@keyframes slideUp{from{transform:translateY(100%);}to{transform:translateY(0);}}
.modal-handle{width:40px;height:4px;background:var(--border);border-radius:2px;margin:0 auto 24px;}
.modal h3{font-size:20px;font-weight:800;margin-bottom:8px;}
.modal p{font-size:14px;color:var(--muted);line-height:1.6;font-family:'DM Mono',monospace;margin-bottom:24px;}
.modal-btns{display:flex;gap:10px;}
.modal-btns button{flex:1;padding:14px;border-radius:12px;font-family:'Syne',sans-serif;font-size:14px;font-weight:700;cursor:pointer;border:none;}
.modal-btn-cancel{background:var(--surface);color:var(--muted);border:1.5px solid var(--border)!important;}
.modal-btn-open{background:var(--accent2);color:#fff;}
`;
